/// <summary>
///
/// </summary>
public static FWFTextBlockGroupAssign findByGroupIdRefId(
    FWFTextBlockGroupId	_groupId,
    FWFTextBlockRefId	_refId,
    boolean				_forUpdate = false)
{
    FWFTextBlockGroupAssign  textBlockGroupAssign;

    textBlockGroupAssign.selectForUpdate(_forUpdate);

    if (_groupId && _refId)
    {
        select firstOnly textBlockGroupAssign
            where textBlockGroupAssign.GroupId == _groupId
               && textBlockGroupAssign.RefId   == _refId;
    }

    return textBlockGroupAssign;
}

static server container selectedReferences(
    FWFTextBlockGroupId _groupId,
    FWFTextBlockModule	_module
    )
{
    container				ret;
    container				data;
    CustTable				custTable;
    VendTable				vendTable;
    InventTable				inventTable;
    ProjTable				projTable;
    FWFTextBlockGroupAssign groupList;

    switch (_module)
    {
        case FWFTextBlockModule::Customer :
            while select custTable order by AccountNum
            exists join groupList
                where groupList.RefId   == custTable.AccountNum
                   && groupList.GroupId == _groupId
            {
                data = [custTable.AccountNum, custTable.AccountNum, custTable.name()];
                ret += [data];
            }
            break;

        case FWFTextBlockModule::Supplier :
            while select vendTable order by AccountNum
            exists join groupList
                where groupList.RefId   == vendTable.AccountNum
                   && groupList.GroupId == _groupId
            {
                data = [vendTable.AccountNum, vendTable.AccountNum, vendTable.name()];
                ret += [data];
            }
            break;

        case FWFTextBlockModule::ReleasedProduct :
            while select inventTable order by ItemId
            exists join groupList
                where groupList.RefId   == inventTable.ItemId
                   && groupList.GroupId == _groupId
            {
                data = [inventTable.ItemId, inventTable.ItemId, inventTable.NameAlias];
                ret += [data];
            }
            break;

        case FWFTextBlockModule::Project :
            while select projTable order by ProjId
            exists join groupList
                where groupList.RefId   == projTable.ProjId
                   && groupList.GroupId == _groupId
            {
                data = [projTable.ProjId, projTable.ProjId, projTable.Name];
                ret += [data];
            }
            break;
    }

    return ret;
}

static server container availableReferences(
    FWFTextBlockGroupId _groupId,
    FWFTextBlockModule	_module
    )
{
    container				ret;
    container				data;
    CustTable				custTable;
    VendTable				vendTable;
    InventTable				inventTable;
    ProjTable				projTable;
    FWFTextBlockGroupAssign groupList;

    switch (_module)
    {
        case FWFTextBlockModule::Customer :
            while select custTable order by AccountNum
            notExists join firstOnly groupList
                where groupList.RefId   == custTable.AccountNum
                   && groupList.GroupId == _groupId
            {
                data = [custTable.AccountNum, custTable.AccountNum, custTable.name()];
                ret += [data];
            }
            break;

        case FWFTextBlockModule::Supplier :
            while select vendTable order by AccountNum
            notExists join firstOnly groupList
                where groupList.RefId   == vendTable.AccountNum
                   && groupList.GroupId == _groupId
            {
                data = [vendTable.AccountNum, vendTable.AccountNum, vendTable.name()];
                ret += [data];
            }
            break;

        case FWFTextBlockModule::ReleasedProduct :
            while select inventTable order by ItemId
            notExists join groupList
                where groupList.RefId   == inventTable.ItemId
                   && groupList.GroupId == _groupId
            {
                data = [inventTable.ItemId, inventTable.ItemId, inventTable.NameAlias];
                ret += [data];
            }
            break;

        case FWFTextBlockModule::Project :
            while select projTable order by ProjId
            notExists join groupList
                where groupList.RefId   == projTable.ProjId
                   && groupList.GroupId == _groupId
            {
                data = [projTable.ProjId, projTable.ProjId, projTable.Name];
                ret += [data];
            }
            break;
    }
    return ret;
}

public static boolean exists(
    FWFTextBlockGroupId	_groupId,
    FWFTextBlockRefId	_refId)
{
    FWFTextBlockGroupAssign  textBlockGroupAssign;

    if (_groupId && _refId)
    {
        select firstOnly textBlockGroupAssign
            where textBlockGroupAssign.GroupId == _groupId
               && textBlockGroupAssign.RefId   == _refId;
    }

    return textBlockGroupAssign.RecId != 0;
}

/// <summary>
///
/// </summary>
public static FWFTextBlockGroupAssign insertTextBlockGroupAssign(
    FWFTextBlockGroupId	_groupId,
    FWFTextBlockModule  _module,
    FWFTextBlockRefId	_refId
    )
{
    FWFTextBlockGroupAssign	newTextBlockGroupAssign;
    FWFTextBlockGroupAssign selectedTextBlockGroupAssign;

    select firstonly RecId from selectedTextBlockGroupAssign
        where selectedTextBlockGroupAssign.GroupId  == _groupId
           && selectedTextBlockGroupAssign.Module   == _module
           && selectedTextBlockGroupAssign.RefId	== _refId;

    if (! selectedTextBlockGroupAssign.RecId)
    {
        newTextBlockGroupAssign = null;
        newTextBlockGroupAssign.initValue();
        newTextBlockGroupAssign.GroupId = _groupId;
        newTextBlockGroupAssign.Module  = _module;
        newTextBlockGroupAssign.RefId	= _refId;
        newTextBlockGroupAssign.insert();
    }
    else
    {
        error (strFmt("@FWFTextBlock:TextBlockGroupAssignInsertError", _module, _refId, _groupId));
    }

    return newTextBlockGroupAssign;
}

/// <summary>
///
/// </summary>
display Name name()
{
    CustTable	custTable;
    VendTable	vendTable;
    InventTable	inventTable;
    ProjTable	projTable;

    switch (this.Module)
    {
        case FWFTextBlockModule::Customer :
            select firstonly Party from custTable
                where custTable.AccountNum == this.RefId;
            return custTable.name();

        case FWFTextBlockModule::Supplier :
            select firstonly Party from vendTable
                where vendTable.AccountNum == this.RefId;
            return vendTable.name();

        case FWFTextBlockModule::ReleasedProduct :
            select firstonly NameAlias from inventTable
                where inventTable.ItemId == this.RefId;
            return inventTable.NameAlias;

        case FWFTextBlockModule::Project :
            select firstonly Name from projTable
                where projTable.ProjId == this.RefId;
            return projTable.Name;

    }

    return '';

}
